        # Heap is ordered by priority (lowest first), then by insertion order.
        count = next(self._counter)
        heapq.heappush(self._queue, (task.priority, count, task))

    def execute(self):
        while self._queue:
            priority, count, task = heapq.heappop(self._queue)
            try:
