import heapq
import itertools
import traceback

class Task:
    def __init__(self, func, args=None, kwargs=None, priority=10, max_retries=3):
        self.func = func
        self.args = args or ()
        self.kwargs = kwargs or {}
        self.priority = priority
        self.retries = 0
        self.max_retries = max_retries

    def execute(self):
        return self.func(*self.args, **self.kwargs)

class TaskQueue:
    def __init__(self):
        self._queue = []
        self._counter = itertools.count()

    def add_task(self, func, args=None, kwargs=None, priority=10):
        task = Task(func, args, kwargs, priority)
        count = next(self._counter)
        # heapq sorts by tuple order: first by priority, then by count.
        heapq.heappush(self._queue, (priority, count, task))

    def run(self):
        while self._queue:
            _, _, task = heapq.heappop(self._queue)
            try:
                print(f"Executing task: {task.func.__name__} (Attempt {task.retries+1})")
                task.execute()
            except Exception as e:
                task.retries += 1
                print(f"Task {task.func.__name__} failed on attempt {task.retries}: {e}")
                traceback.print_exc()
                if task.retries < task.max_retries:
                    # re-add task to the queue. Optionally, you can change the priority if desired.
                    count = next(self._counter)
                    heapq.heappush(self._queue, (task.priority, count, task))
                else:
                    print(f"Task {task.func.__name__} reached max retries and will be dropped.")

