import heapq
from dataclasses import dataclass, field
import traceback

@dataclass(order=True)
class Task:
    priority: int
    counter: int
    # The following fields are not used for comparison
    attempts: int = field(default=0, compare=False)
    func: callable = field(default=None, compare=False)
    args: tuple = field(default_factory=tuple, compare=False)
    kwargs: dict = field(default_factory=dict, compare=False)

class TaskQueue:
    def __init__(self):
        self._queue = []
        self._counter = 0  # Unique counter to maintain FIFO order for same priority

    def add_task(self, func, args=(), kwargs=None, priority=0):
        if kwargs is None:
            kwargs = {}
        task = Task(priority, self._counter, 0, func, args, kwargs)
        self._counter += 1
        heapq.heappush(self._queue, task)

    def execute_all(self):
        while self._queue:
            task = heapq.heappop(self._queue)
            try:
                # Execute the task function with provided arguments
                task.func(*task.args, **task.kwargs)
            except Exception as ex:
                print(f"Task {task.func.__name__} raised an exception: {ex}")
                traceback.print_exc()
                if task.attempts < 2:  # Attempt count starts at 0 so up to 3 tries in total
                    task.attempts += 1
                    print(f"Retrying task {task.func.__name__} (attempt {task.attempts + 1} of 3)...")
                    # Reinsert the task into the queue. We use the same priority and update counter to maintain order.
                    task.counter = self._counter
                    self._counter += 1
                    heapq.heappush(self._queue, task)
                else:
                    print(f"Task {task.func.__name__} failed after 3 attempts. Skipping.")
            else:
                print(f"Task {task.func.__name__} executed successfully.")

